import React from 'react';
import { Link } from 'react-router-dom';
import { Trash2, Heart, ShoppingCart } from 'lucide-react';
// Assuming you have a useWishlist hook similar to useCart
import { useWishlist } from '../hooks/useWishlist';
// import { useCart } from '../hooks/usecart'; // Uncomment if you want to wire up the Add to Cart button

const WishlistPage = () => {
    const { items, removeItem } = useWishlist();
    // const { addItem } = useCart(); // Optional: Pull this in to make the "Add to Cart" button functional

    if (items.length === 0) {
        return (
            <div className="min-h-[60vh] flex flex-col items-center justify-center px-4">
                <Heart className="w-16 h-16 text-gray-300 mb-4" />
                <h2 className="text-xl font-semibold text-gray-900 mb-2">
                    Your wishlist is empty
                </h2>
                <p className="text-gray-500 mb-6">
                    Save items you love here to easily find them later.
                </p>
                <Link
                    to="/"
                    className="bg-primary-700 text-white px-6 py-2.5 rounded-lg font-medium hover:bg-primary-800 transition"
                >
                    Discover Products
                </Link>
            </div>
        );
    }

    return (
        <div className="container mx-auto px-4 py-6 md:py-10">
            <h1 className="text-2xl font-bold text-gray-900 mb-6">
                My Wishlist ({items.length} {items.length === 1 ? 'item' : 'items'})
            </h1>

            {/* Changed layout to a centered max-width since the summary sidebar is gone */}
            <div className="max-w-4xl space-y-4">
                {items.map((item) => (
                    <div
                        key={`${item.productId}_${item.variantId}`}
                        className="bg-white rounded-xl p-4 shadow-sm border border-gray-100 flex gap-4"
                    >
                        <div className="w-24 h-24 md:w-32 md:h-32 bg-gray-100 rounded-lg overflow-hidden flex-shrink-0">
                            <img
                                src={item.image}
                                alt={item.name}
                                className="w-full h-full object-cover"
                            />
                        </div>

                        <div className="flex-grow min-w-0">
                            <div className="flex justify-between items-start">
                                <div>
                                    <h3 className="font-medium text-gray-900 truncate">
                                        {item.name}
                                    </h3>
                                    {item.variantId && (
                                        <p className="text-sm text-gray-500 mt-0.5">
                                            Variant: {item.variantId}
                                        </p>
                                    )}
                                </div>
                                <button
                                    onClick={() => removeItem(item.productId, item.variantId)}
                                    className="p-1.5 text-gray-400 hover:text-red-500 transition"
                                    title="Remove from wishlist"
                                >
                                    <Trash2 className="w-5 h-5" />
                                </button>
                            </div>

                            <div className="flex items-end justify-between mt-4">
                                <div className="flex items-center">
                                    <button
                                        // onClick={() => addItem(item)} // Wire this up to your cart context
                                        className="flex items-center gap-2 bg-gray-100 text-gray-900 px-4 py-2 rounded-lg text-sm font-medium hover:bg-gray-200 transition active:scale-[0.98]"
                                    >
                                        <ShoppingCart className="w-4 h-4" />
                                        <span className="hidden sm:inline">Add to Cart</span>
                                    </button>
                                </div>

                                <div className="text-right">
                                    <p className="font-bold text-lg text-gray-900">
                                        ₹{item.price.toLocaleString()}
                                    </p>
                                </div>
                            </div>
                        </div>
                    </div>
                ))}
            </div>
        </div>
    );
};

export default WishlistPage;
